import React, { useState, useEffect, createContext, useContext } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import Navbar from './components/Navbar';
import HomePage from './pages/HomePage';
import LoginPage from './pages/LoginPage';
import RegisterPage from './pages/RegisterPage';
import WorkshopTypesPage from './pages/WorkshopTypesPage';
import WorkshopDetailsPage from './pages/WorkshopDetailsPage';
import ProposeWorkshopPage from './pages/ProposeWorkshopPage';
import WorkshopStatusPage from './pages/WorkshopStatusPage';
import ProfilePage from './pages/ProfilePage';
import './App.css';

export const AuthContext = createContext(null);

export function useAuth() {
  return useContext(AuthContext);
}

// Mock auth state for demo
function App() {
  const [user, setUser] = useState(null);
  const [toasts, setToasts] = useState([]);

  const login = (userData) => setUser(userData);
  const logout = () => setUser(null);

  const addToast = (message, type = 'info') => {
    const id = Date.now();
    setToasts(prev => [...prev, { id, message, type }]);
    setTimeout(() => setToasts(prev => prev.filter(t => t.id !== id)), 4000);
  };

  return (
    <AuthContext.Provider value={{ user, login, logout, addToast }}>
      <Router>
        <div className="app">
          <Navbar />
          <main className="main-content" role="main">
            <Routes>
              <Route path="/" element={<HomePage />} />
              <Route path="/login" element={<LoginPage />} />
              <Route path="/register" element={<RegisterPage />} />
              <Route path="/workshop-types" element={<WorkshopTypesPage />} />
              <Route path="/workshop-types/:id" element={<WorkshopDetailsPage />} />
              <Route path="/propose" element={<ProposeWorkshopPage />} />
              <Route path="/my-workshops" element={<WorkshopStatusPage />} />
              <Route path="/profile" element={<ProfilePage />} />
              <Route path="*" element={<Navigate to="/" />} />
            </Routes>
          </main>
          <Footer />
          <ToastContainer toasts={toasts} />
        </div>
      </Router>
    </AuthContext.Provider>
  );
}

function Footer() {
  return (
    <footer className="site-footer" role="contentinfo">
      <div className="container">
        <div className="footer-inner">
          <div className="footer-brand">
            <span className="footer-logo">FOSSEE</span>
            <p>Free and Open Source Software for Education</p>
          </div>
          <div className="footer-links">
            <a href="https://fossee.in" target="_blank" rel="noopener noreferrer">fossee.in</a>
            <a href="https://iitb.ac.in" target="_blank" rel="noopener noreferrer">IIT Bombay</a>
          </div>
        </div>
        <div className="footer-copy">
          <p>© {new Date().getFullYear()} FOSSEE Group, IIT Bombay. All rights reserved.</p>
        </div>
      </div>
    </footer>
  );
}

function ToastContainer({ toasts }) {
  return (
    <div className="toast-container" aria-live="polite" aria-atomic="true">
      {toasts.map(t => (
        <div key={t.id} className={`toast toast-${t.type}`} role="alert">
          <span className="toast-icon">
            {t.type === 'success' ? '✓' : t.type === 'error' ? '✕' : 'ℹ'}
          </span>
          {t.message}
        </div>
      ))}
    </div>
  );
}

export default App;
